                    a[j] = v;
                }
            }
            return;
        }
        int m = l + (h - l) / 2;
        if (a[m] < a[l]) std::swap(a[m], a[l]);
        if (a[h] < a[l]) std::swap(a[h], a[l]);
        if (a[h] < a[m]) std::swap(a[h], a[m]);
        int p = a[m], i = l - 1, j = h + 1;
        while (1) {
